const CONFIG={OBSERVER_THRESHOLD:[0,.2],RAF_FALLBACK_MS:16,FONT_LOAD_TIMEOUT_MS:1500,SELECTORS:{header:"header",heroH1:".hero h1",headerTitleWrapper:".header-title-wrapper",headerTitleLink:".header-title-link",skipLinkHeader:".skip-link-header",mainContent:"#main-content"},CSS_VARS:{headerHeight:"--header-height"},HERO_SVG:{pointsPerCircle:200,fbmOctaves:3,radiusSafetyFactor:.95,viewboxFactor:2.1}};function installRequestAnimationFramePolyfill(){try{if(!window){return}if(!window.requestAnimationFrame){window.requestAnimationFrame=function(callback){if(typeof callback!=="function"){return null}return setTimeout(callback,16)}}if(!window.cancelAnimationFrame){window.cancelAnimationFrame=function(id){if(typeof id!=="number"){return}return clearTimeout(id)}}}catch(error){void error}}function updateHeaderHeight(){try{if(!CONFIG||!CONFIG.SELECTORS||!CONFIG.CSS_VARS){return}const header=document.querySelector(CONFIG.SELECTORS.header);if(!header){return}const height=header.offsetHeight;if(!Number.isFinite(height)||height<=0){return}document.documentElement.style.setProperty(CONFIG.CSS_VARS.headerHeight,`${height}px`)}catch(error){void error}}function initHeaderListener(){try{updateHeaderHeight();let resizeTimer;const debouncedUpdate=()=>{clearTimeout(resizeTimer);resizeTimer=setTimeout(updateHeaderHeight,100)};window.addEventListener("resize",debouncedUpdate);if(document.fonts&&document.fonts.ready){document.fonts.ready.then(()=>{updateHeaderHeight()}).catch(()=>{setTimeout(updateHeaderHeight,CONFIG.FONT_LOAD_TIMEOUT_MS)})}else{setTimeout(updateHeaderHeight,CONFIG.FONT_LOAD_TIMEOUT_MS)}}catch(error){void error}}let lastLogoState=false;function setupObserver(){try{if(!CONFIG?.SELECTORS||!CONFIG?.OBSERVER_THRESHOLD){return}if(!window.IntersectionObserver){return}const heroTitle=document.querySelector(CONFIG.SELECTORS.heroH1);const titleWrapper=document.querySelector(CONFIG.SELECTORS.headerTitleWrapper);const titleLink=document.querySelector(CONFIG.SELECTORS.headerTitleLink);if(heroTitle&&titleWrapper){try{const observer=new IntersectionObserver(entries=>{try{entries.forEach(entry=>{const shouldShowHeaderTitle=entry.intersectionRatio<.2;if(shouldShowHeaderTitle!==lastLogoState){if(shouldShowHeaderTitle){titleWrapper.classList.add("visible");if(titleLink){titleLink.setAttribute("aria-hidden","false");titleLink.setAttribute("tabindex","0")}}else{titleWrapper.classList.remove("visible");if(titleLink){titleLink.setAttribute("aria-hidden","true");titleLink.setAttribute("tabindex","-1")}}lastLogoState=shouldShowHeaderTitle}})}catch(error){void error}},{threshold:CONFIG.OBSERVER_THRESHOLD});observer.observe(heroTitle)}catch(error){void error}}const sections=document.querySelectorAll("section[id]");const navLinks=document.querySelectorAll('nav a[href^="#"]');if(sections.length>0&&navLinks.length>0){try{const sectionMap={};navLinks.forEach(link=>{const href=link.getAttribute("href");if(href&&href.startsWith("#")){const sectionId=href.slice(1);sectionMap[sectionId]=link}});const headerHeightPx=parseInt(getComputedStyle(document.documentElement).getPropertyValue("--header-height"))||85;const sectionObserver=new IntersectionObserver(entries=>{try{entries.forEach(entry=>{const sectionId=entry.target.id;const link=sectionMap[sectionId];if(!link){return}if(entry.isIntersecting){navLinks.forEach(l=>{l.removeAttribute("aria-current")});link.setAttribute("aria-current","page")}})}catch(error){void error}},{rootMargin:`-${headerHeightPx}px 0px -66% 0px`,threshold:[0,.5]});sections.forEach(section=>{try{sectionObserver.observe(section)}catch(error){void error}})}catch(error){void error}}}catch(error){void error}}function __resetObserverState(){lastLogoState=false}const HERO_SVG_PALETTE=["#8B3A3A","#7A2F2F","#6B2424","#5A1A1A","#4A1515","#3A0F0F","#2A0A0A","#1a0505","#0a0000"];function setupHeroCircles(){const ghirondaImg=document.querySelector(".ghironda-icon");const ghirondaWrapper=document.querySelector(".ghironda-wrapper");if(!ghirondaImg){return}if(!ghirondaWrapper){return}let lastSvgUrl=null;let rafRetries=0;const RAF_MAX_RETRIES=300;function generateCircles(){try{const rect=ghirondaImg.getBoundingClientRect();const width=rect.width;const height=rect.height;if(width===0||height===0){rafRetries+=1;if(rafRetries<RAF_MAX_RETRIES){requestAnimationFrame(generateCircles)}return}rafRetries=0;const diagonal=Math.sqrt(width*width+height*height);const r1=diagonal/2;const heroRect=ghirondaImg.closest(".hero").getBoundingClientRect();const imgCenterX=rect.left+width/2;const imgCenterY=rect.top+height/2;const distTopLeft=Math.sqrt((imgCenterX-heroRect.left)**2+(imgCenterY-heroRect.top)**2);const distTopRight=Math.sqrt((heroRect.right-imgCenterX)**2+(imgCenterY-heroRect.top)**2);const distBottomLeft=Math.sqrt((imgCenterX-heroRect.left)**2+(heroRect.bottom-imgCenterY)**2);const distBottomRight=Math.sqrt((heroRect.right-imgCenterX)**2+(heroRect.bottom-imgCenterY)**2);const r9=Math.max(distTopLeft,distTopRight,distBottomLeft,distBottomRight)*CONFIG.HERO_SVG.radiusSafetyFactor;const ratio=Math.pow(r9/r1,1/8);let circlesHtml="";for(let i=8;i>=0;i--){const baseRadius=r1*Math.pow(ratio,i);const numPoints=CONFIG.HERO_SVG.pointsPerCircle;const maxAmplitude=baseRadius*(.04+i*.01);const baseFrequency=2;const numOctaves=CONFIG.HERO_SVG.fbmOctaves;let pathD="";for(let j=0;j<=numPoints;j++){const angle=j/numPoints*Math.PI*2;let perturbation=0;let amplitude=maxAmplitude;let frequency=baseFrequency;for(let octave=0;octave<numOctaves;octave++){perturbation+=Math.sin(angle*frequency)*amplitude;frequency*=2;amplitude*=.5}const radius=baseRadius+perturbation;const x=radius*Math.cos(angle);const y=radius*Math.sin(angle);pathD+=(j===0?"M":"L")+x.toFixed(1)+","+y.toFixed(1)}pathD+="Z";const fillOpacity=.8-i*.08;circlesHtml+='<path d="'+pathD+'" fill="'+HERO_SVG_PALETTE[8-i]+'" fill-opacity="'+fillOpacity.toFixed(3)+'" stroke="none"/>';const sw=2.2+i/8*3.5;const baseStrokeOpacity=.95-i*.07;const strokeOpacity=Math.max(baseStrokeOpacity,.4);const strokeColor=i===0?"#000000":"#330000";circlesHtml+='<path d="'+pathD+'" fill="none" stroke="'+strokeColor+'" stroke-width="'+sw.toFixed(1)+'" opacity="'+strokeOpacity.toFixed(2)+'" stroke-linecap="round" stroke-linejoin="round"/>'}const vb=r9*CONFIG.HERO_SVG.viewboxFactor;const vbHalf=Math.floor(vb/2);const svgHtml='<svg xmlns="http://www.w3.org/2000/svg" viewBox="'+-vbHalf+" "+-vbHalf+" "+Math.ceil(vb)+" "+Math.ceil(vb)+'" width="'+Math.ceil(vb)+'" height="'+Math.ceil(vb)+'"><g>'+circlesHtml+"</g></svg>";const svgUrl="url('data:image/svg+xml;utf8,"+encodeURIComponent(svgHtml)+"')";if(svgUrl!==lastSvgUrl){lastSvgUrl=svgUrl;ghirondaWrapper.style.setProperty("--ghironda-circles",svgUrl);ghirondaWrapper.style.setProperty("--circle-size",Math.ceil(vb)+"px")}}catch(error){void error}}if(ghirondaImg.complete&&ghirondaImg.naturalWidth>0){generateCircles()}else{ghirondaImg.addEventListener("load",()=>{generateCircles()})}let resizeTimer;window.addEventListener("resize",()=>{clearTimeout(resizeTimer);resizeTimer=setTimeout(generateCircles,500)})}try{if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",()=>{try{initHeaderListener();setupObserver();if("requestIdleCallback"in window){requestIdleCallback(()=>{try{setupHeroCircles()}catch(error){void error}})}else{setTimeout(()=>{try{setupHeroCircles()}catch(error){void error}},1e3)}}catch(error){void error}})}else{try{initHeaderListener();setupObserver();if("requestIdleCallback"in window){requestIdleCallback(()=>{try{setupHeroCircles()}catch(error){void error}})}else{setTimeout(()=>{try{setupHeroCircles()}catch(error){void error}},1e3)}}catch(error){void error}}}catch(error){void error}